import re
import math

document_text = """
... (your document text here)
"""

figures = re.findall(r'(\d{1,3}(?:,\d{3})*(?:\.\d+)?)', document_text)

revenue_fy25 = None
total_expenses = None
profit_before_tax = None
total_tax_expense = None
profit_after_tax = None
current_assets_total = None
current_liabilities_total = None
debt_equity_ratio = None
interest_expense = None
operating_cash_flow = None

for figure in figures:
    if 'revenue' in document_text.lower() or 'total income' in document_text.lower():
        revenue_fy25 = float(figure.replace(',', ''))
    elif 'total expenses' in document_text.lower():
        total_expenses = float(figure.replace(',', ''))
    elif 'profit before tax' in document_text.lower():
        profit_before_tax = float(figure.replace(',', ''))
    elif 'total tax expense' in document_text.lower():
        total_tax_expense = float(figure.replace(',', ''))
    elif 'profit after tax' in document_text.lower():
        profit_after_tax = float(figure.replace(',', ''))
    elif 'current assets' in document_text.lower():
        current_assets_total = float(figure.replace(',', ''))
    elif 'current liabilities' in document_text.lower():
        current_liabilities_total = float(figure.replace(',', ''))
    elif 'debt equity ratio' in document_text.lower():
        debt_equity_ratio = float(figure.replace(',', ''))
    elif 'interest expense' in document_text.lower():
        interest_expense = float(figure.replace(',', ''))
    elif 'operating cash flow' in document_text.lower():
        operating_cash_flow = float(figure.replace(',', ''))

if revenue_fy25:
    print(f"Revenue FY25: INR {revenue_fy25:,.2f} Cr")
if total_expenses:
    print(f"Total Expenses: INR {total_expenses:,.2f} Cr")
if profit_before_tax:
    print(f"Profit Before Tax: INR {profit_before_tax:,.2f} Cr")
if total_tax_expense:
    print(f"Total Tax Expense: INR {total_tax_expense:,.2f} Cr")
if profit_after_tax:
    print(f"Profit After Tax: INR {profit_after_tax:,.2f} Cr")
if current_assets_total:
    print(f"Current Assets Total: INR {current_assets_total:,.2f} Cr")
if current_liabilities_total:
    print(f"Current Liabilities Total: INR {current_liabilities_total:,.2f} Cr")
if debt_equity_ratio:
    print(f"Debt Equity Ratio: {debt_equity_ratio:.2f}")
if interest_expense:
    print(f"Interest Expense: INR {interest_expense:,.2f} Cr")
if operating_cash_flow:
    print(f"Operating Cash Flow: INR {operating_cash_flow:,.2f} Cr")

current_ratio = current_assets_total / current_liabilities_total if current_assets_total and current_liabilities_total else "N/A — not found"
debt_equity = debt_equity_ratio
net_profit_margin_pct = (profit_after_tax / revenue_fy25) * 100 if revenue_fy25 and profit_after_tax else "N/A — not found"
interest_coverage = profit_before_tax / interest_expense if profit_before_tax and interest_expense else "N/A — not found"
working_capital = current_assets_total - current_liabilities_total if current_assets_total and current_liabilities_total else "N/A — not found"
dscr = operating_cash_flow / (interest_expense + total_tax_expense) if operating_cash_flow and interest_expense and total_tax_expense else "N/A — not found"

print(f"Net Profit Margin %: {net_profit_margin_pct}")
print(f"Current Ratio: {current_ratio}")
print(f"Debt Equity Ratio: {debt_equity_ratio}")
print(f"Interest Coverage: {interest_coverage}")
print(f"Working Capital: {working_capital}")
print(f"DSCR: {dscr}")

if current_ratio != "N/A — not found" and current_ratio < 1:
    print("WARNING: Current Ratio < 1")
if debt_equity_ratio != "N/A — not found" and debt_equity_ratio > 3:
    print("WARNING: Debt Equity Ratio > 3")
if operating_cash_flow != "N/A — not found" and operating_cash_flow < 0:
    print("WARNING: Negative Operating Cash Flow")

if not any(var for var in [revenue_fy25, total_expenses, profit_before_tax, total_tax_expense, profit_after_tax, current_assets_total, current_liabilities_total, debt_equity_ratio, interest_expense, operating_cash_flow]):
    print("WARNING: No specific financial figures extracted from this document.")

